{"element_id":"7349cd7","elType":"widget","widgetType":"html","settings":{"html":"<style>
/* Home 2026 Hero: decorative blobs + floating card (scoped) */
.home-2026-hero-blob{position:absolute;filter:blur(48px);opacity:.65;z-index:0;pointer-events:none;}
.home-2026-hero-blob.b1{width:260px;height:260px;right:-56px;top:-56px;background:rgba(240,107,26,.28);border-radius:999px;}
.home-2026-hero-blob.b2{width:210px;height:210px;left:-56px;bottom:-56px;background:rgba(74,225,131,.18);border-radius:999px;}
.home-2026-hero-float{position:absolute;left:-18px;bottom:-18px;max-width:260px;z-index:2;backdrop-filter:blur(18px);-webkit-backdrop-filter:blur(18px);background:rgba(255,255,255,.78);border:1px solid rgba(255,255,255,.55);border-radius:18px;box-shadow:0 18px 50px rgba(20,20,20,.14);padding:16px;}
.home-2026-hero-float .hdr{display:flex;align-items:center;gap:10px;margin-bottom:8px;}
.home-2026-hero-float .ico{width:40px;height:40px;border-radius:999px;background:rgba(255,219,202,.9);display:flex;align-items:center;justify-content:center;font-size:18px;flex:0 0 auto;}
.home-2026-hero-float .t{font-weight:800;font-size:14px;color:#231a15;line-height:1;}
.home-2026-hero-float .d{font-size:12px;color:rgba(86,67,57,.95);line-height:1.35;margin:0 0 10px;}
.home-2026-hero-float .btm{display:flex;align-items:center;justify-content:space-between;gap:10px;}
.home-2026-hero-float .price{font-weight:800;color:#F06B1A;font-size:12.5px;white-space:nowrap;}
.home-2026-hero-float .badge{font-size:10px;font-weight:800;letter-spacing:.08em;text-transform:uppercase;background:rgba(0,109,55,.10);color:#006d37;padding:4px 8px;border-radius:999px;white-space:nowrap;}
@media (max-width: 767px){
  .home-2026-hero-float{left:8px;bottom:8px;max-width:240px;padding:14px;}
}
</style>
<div class="home-2026-hero-blob b1"></div>
<div class="home-2026-hero-blob b2"></div>
<div class="home-2026-hero-float">
  <div class="hdr">
    <div class="ico">🍽️</div>
    <div class="t">Chef’s Special</div>
  </div>
  <p class="d">Maharaja Thali (Non-veg) — Combination of 7 items</p>
  <div class="btm">
    <div class="price">From $15.00 CAD</div>
    <div class="badge">High Protein</div>
  </div>
</div>"}}
